139→const TASK_PROMPT = `
140→- The FIRST thing you MUST do is write your understanding of each WORKFLOW AND CRITICAL statement
141→- The SECOND thing you MUST do is write your understanding of the work in progress described in progress.txt
142→- Only AFTER completing steps above, proceed with the task execution
143→
144→WORKFLOW:
145→0. Understand Project
146→1. Read ./.claude/progress.txt and identify the most important pending task;
147→   - Specific task prioritization is indicated/tagged/prefixed with '[P'+number+']'
148→   - Tasks tagged with '[P0]' must be done before anything else.
149→   - Tasks tagged with P bigger than 999 (e.g. '[P1000]'), are low-priority 
150→   tasks, they should be done when possible, but they must be done 
151→   (they are not ignorable); If the task takes longer and there are other 
152→   non-low-priority tasks, document progress and revert the status to "- [ ]".
153→   
154→2. If NO pending tasks exist, plan next improvements, add tasks and stop
155→3. If there are tasks, mark it as IN_PROGRESS and then sequentially run:
156→   - Evaluate scope: if the task involves more than ~3 files or multiple concerns,
157→      break it into smaller sub-tasks in progress.txt BEFORE starting. Each sub-task
158→      must be completable in a single iteration (small, atomic, committable change).
159→   - Execute task
160→   - Run 'bun run check' and fix found issues.     
161→   - Launch 1 review agents to deeply review the work, giving
162→      the entire context of the task, simulating pull request.
163→   - Review output and consider improvements
164→   - Implement corrections if needed
165→   - Update progress.txt marking task as completed
166→   - Commit task changes (not include unrelated code)
167→   - Output status block (see below)
168→   - Stop
169→
170→CRITICAL:
171→- ALL tasks and instructions are deliberate. 
172→- No task is optional.
173→- If more work is necessary, add a new task to the file, set "exit": false, and Stop
174→- Only set "exit": true when ALL tasks in progress.txt are completed
175→- Never remove tasks, unless to update status;
176→- Never include workarounds and add tasks to fix all you found ('as any' for example is a workaround)
177→- No task should be submitted as "look reasonable." 
178→- Every task must be delivered with professional quality, without any makeshift solutions.
179→- For tasks with visual parts, full visual and interaction tests with Playwright MCP are required.
180→- Never consider any mistake or error to be expected or acceptable.- Never consider any mistake or error to be expected or acceptable.
181→- Never trust project comments or documentation without confirming on actual 
182→code.
183→
184→--------------------------------------------------------------------------------
185→
186→OUTPUT STATUS (REQUIRED at end of EVERY response):
187→You MUST output this exact format at the END of your response:
188→
189→RALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
190→
191→Examples:
192→- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
193→- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
194→
195→`;
196→
197→interface ContentBlock {
198→  type: 'text' | 'tool_use' | 'tool_result';
199→  text?: string;
200→  name?: string;
201→  input?: unknown;
202→  content?:
203→    | string
204→    | Array<{
205→        type: string;
206→        text?: string;
207→      }>;
208→}
209→
210→interface StreamMessage {
211→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
212→  subtype?: string;
213→  role?: 'assistant' | 'user';
214→  event?: {
215→    type: string;
216→    delta?: {
217→      type: string;
218→      text?: string;
219→    };
220→  };
221→  result?: string;
222→  message?: {
223→    role?: string;
224→    content?: ContentBlock[];
225→  };
226→  content?: ContentBlock[];
227→}
228→
229→interface RalphStatus {
230→  exit: boolean;
231→  task: string;
232→  remaining: number;
233→}
234→
235→function parseRalphStatus(output: string): RalphStatus | null {
236→  const marker = output.lastIndexOf('RALPH_STATUS:');
237→  if (marker === -1) return null;
238→
239→  const jsonStart = output.indexOf('{', marker);
240→  if (jsonStart === -1) return null;
241→
242→  let depth = 0;
243→  for (let i = jsonStart; i < output.length; i++) {
244→    if (output[i] === '{') depth++;
245→    if (output[i] === '}') depth--;
246→    if (depth === 0) {
247→      try {
248→        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
249→        if (typeof parsed.exit === 'boolean') {
250→          return parsed as RalphStatus;
251→        }
252→      } catch {}
253→      return null;
254→    }
255→  }
256→  return null;
257→}
258→
259→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
260→
261→function killCurrentProc(): void {
262→  if (!currentProc) return;
263→  try {
264→    currentProc.kill();
265→  } catch {}
266→}
