268→async function checkDependencies(): Promise<void> {
269→  const result = await Bun.$`which claude`.quiet().nothrow();
270→  if (result.exitCode !== 0) {
271→    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
272→    process.exit(1);
273→  }
274→
275→  if (!(await Bun.file(CONFIG.progressFile).exists())) {
276→    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
277→    process.exit(1);
278→  }
279→}
280→
281→interface IterationResult {
282→  output: string;
283→  exitCode: number;
284→  timedOut: boolean;
285→}
286→
287→async function runIteration(): Promise<IterationResult> {
288→  syslog('Executing Claude Code...');
289→
290→  const proc = Bun.spawn(
291→    [
292→      'claude',
293→      '-p',
294→      TASK_PROMPT,
295→      '--verbose',
296→      '--debug',
297→      '--dangerously-skip-permissions',
298→      '--output-format',
299→      'stream-json',
300→      '--include-partial-messages',
301→      '--model=opus',
302→    ],
303→    {
304→      cwd: process.cwd(),
305→      env: process.env,
306→      stdout: 'pipe',
307→      stderr: 'inherit',
308→    },
309→  );
310→
311→  currentProc = proc;
312→
313→  const chunks: string[] = [];
314→  let timedOut = false;
315→  const decoder = new TextDecoder();
316→  let buffer = '';
317→  let blockHasContent = false;
318→
319→  const timeoutId = setTimeout(() => {
320→    timedOut = true;
321→    syslog('Iteration timeout reached. Killing process...', 'yellow');
322→    killCurrentProc();
323→  }, CONFIG.iterationTimeout);
324→
325→  const reader = proc.stdout.getReader();
326→
327→  try {
328→    while (true) {
329→      const { done, value } = await reader.read();
330→      if (done) break;
331→
332→      buffer += decoder.decode(value, { stream: true });
333→
334→      const lines = buffer.split('\n');
335→      buffer = lines.pop() || '';
336→
337→      for (const line of lines) {
338→        if (!line.trim()) continue;
339→
340→        let msg: StreamMessage;
341→        try {
342→          msg = JSON.parse(line);
343→        } catch {
344→          continue;
345→        }
346→
347→        if (msg.type === 'stream_event') {
348→          const evt = msg.event;
349→          if (!evt) continue;
350→
351→          if (evt.type === 'content_block_start') {
352→            blockHasContent = false;
353→          } else if (evt.type === 'content_block_delta') {
354→            const text = evt.delta?.text;
355→            if (text) {
356→              print(text);
357→              chunks.push(text);
358→              blockHasContent = true;
359→            }
360→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
361→            print('\n');
362→            chunks.push('\n');
363→            blockHasContent = false;
364→          }
365→          continue;
366→        }
367→
368→        if (msg.type === 'assistant' || msg.type === 'message') {
369→          // Content already streamed via content_block_delta events.
370→          // Only print here as fallback if no streaming occurred.
371→          const blocks = msg.message?.content ?? msg.content;
372→          if (!Array.isArray(blocks)) continue;
373→
374→          for (const block of blocks) {
375→            if (block.type === 'text' && block.text && chunks.length === 0) {
376→              print(block.text);
377→              chunks.push(block.text);
378→              print('\n');
379→              chunks.push('\n');
380→            }
381→          }
382→          continue;
383→        }
384→
385→        if (msg.type === 'user') {
386→          const blocks = msg.message?.content ?? msg.content;
387→          if (!Array.isArray(blocks)) continue;
388→
389→          for (const block of blocks) {
390→            //
391→            // Handling tool result
392→            if (block.type === 'tool_result' && block.content) {
393→              const rawContent =
394→                typeof block.content === 'string'
395→                  ? block.content
396→                  : block.content
397→                      .map(c => c.text ?? '')
398→                      .filter(Boolean)
399→                      .join('\n');
400→
401→              if (!rawContent) continue;
402→
403→              let trimmed = rawContent.trim().slice(0, 320);
404→
405→              const toolResult =
406→                trimmed && trimmed !== rawContent
407→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
408→                  : rawContent;
409→
410→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
411→              chunks.push('\n', rawContent, '\n');
412→            }
413→          }
414→          continue;
415→        }
416→
417→        if (msg.type === 'result' && msg.result) {
418→          if (chunks.length === 0) {
419→            chunks.push(msg.result);
420→          }
421→        }
422→      }
423→    }
424→
425→    if (buffer.trim()) {
426→      try {
427→        const msg: StreamMessage = JSON.parse(buffer);
428→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
429→          chunks.push(msg.result);
430→        }
431→      } catch {}
432→    }
433→  } finally {
434→    clearTimeout(timeoutId);
435→    reader.releaseLock();
436→    currentProc = null;
437→    logBuffer.flush();
438→  }
439→
440→  const output = chunks.join('');
441→
442→  if (timedOut) {
443→    return {
444→      output,
445→      exitCode: 124,
446→      timedOut: true,
447→    };
448→  }
449→
450→  const exitCode = await proc.exited;
451→  println();
452→  return {
453→    output,
454→    exitCode,
455→    timedOut: false,
456→  };
457→}
458→
459→function printHeader(): void {
460→  println();
461→  println('==========================================', 'blue');
462→  println('   Ralph Loop - Bun.js Edition', 'blue');
463→  println('==========================================', 'blue');
464→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
465→  println(`Log dir:        ${chalk.yellow(LOG_DIR)}`);
466→  println(
467→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
468→  );
469→  println(
470→    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
471→  );
472→  println();
473→}
474→
475→async function main(): Promise<void> {
476→  let cleanupCalled = false;
477→
478→  const cleanup = (signal: string) => {
479→    if (cleanupCalled) return;
480→    cleanupCalled = true;
481→    println();
482→    syslog(`Interrupted by ${signal}. Cleaning up...`);
483→    killCurrentProc();
484→    logBuffer.dispose();
485→    process.exit(signal === 'SIGINT' ? 130 : 143);
486→  };
487→
488→  process.on('SIGINT', () => cleanup('SIGINT'));
489→  process.on('SIGTERM', () => cleanup('SIGTERM'));
490→
491→  await checkDependencies();
492→
493→  printHeader();
494→  syslog('Starting automated task loop...');
495→
496→  let consecutiveFailures = 0;
497→  const MAX_CONSECUTIVE_FAILURES = 3;
498→
499→  for (let iteration = 1; iteration <= CONFIG.maxIterations; iteration++) {
500→    logBuffer.startNewFile(logFilePath(`iter-${iteration}`));
501→
502→    println();
503→    println('==========================================', 'green');
504→    syslog(`Iteration #${iteration} / ${CONFIG.maxIterations}`, 'green');
505→    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
506→    println('==========================================', 'green');
507→    println();
508→
509→    const { output, exitCode, timedOut } = await runIteration();
510→
511→    if (exitCode === 0) {
512→      syslog('Claude Code completed successfully', 'green');
513→      consecutiveFailures = 0;
514→    } else if (timedOut) {
515→      syslog(
516→        'Iteration timed out — progress may persist in progress.txt',
517→        'yellow',
518→      );
519→    } else {
520→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
521→      consecutiveFailures++;
522→    }
523→
524→    if (consecutiveFailures >= MAX_CONSECUTIVE_FAILURES) {
525→      println();
526→      println('==========================================', 'red');
527→      syslog(
528→        `${MAX_CONSECUTIVE_FAILURES} consecutive failures — aborting loop`,
529→        'red',
530→      );
531→      println('==========================================', 'red');
532→      logBuffer.renameFile(logFilePath('fatal-consecutive-failures'));
533→      logBuffer.dispose();
534→      process.exit(1);
535→    }
536→
537→    const status = parseRalphStatus(output);
538→    const taskSlug = status
539→      ? slugify(status.task)
540→      : timedOut
541→        ? 'timeout'
542→        : 'no-status';
543→    logBuffer.renameFile(logFilePath(taskSlug));
544→
545→    if (status?.exit) {
546→      println();
547→      println('==========================================', 'green');
548→      syslog('ALL TASKS COMPLETED!', 'green');
549→      syslog(`Final task:      ${status.task}`, 'green');
550→      syslog(`Remaining:       ${status.remaining}`, 'green');
551→      syslog(`Total iterations: ${iteration}`, 'green');
552→      println('==========================================', 'green');
553→      logBuffer.dispose();
554→      process.exit(0);
555→    }
556→
557→    if (status) {
558→      syslog(
559→        `Task done: "${status.task}" — ${status.remaining} remaining`,
560→        'blue',
561→      );
562→    } else if (!timedOut && exitCode === 0) {
563→      syslog(
564→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
565→        'yellow',
566→      );
567→    }
568→
569→    if (iteration < CONFIG.maxIterations) {
570→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
571→      println();
572→      syslog(`Waiting ${delaySec}s before next iteration...`);
573→      await Bun.sleep(CONFIG.delayBetweenIterations);
574→    }
575→  }
576→
577→  println();
